namespace sv_88c121f2d1014f65b13134f48251a575.Client.Services;

public interface IShipmentService
{
    Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

public sealed class ShipmentDetails
{
    public required string TrackingNumber { get; init; }
    public required string Status { get; init; }
    public required string Location { get; init; }
    public required DateTimeOffset EstimatedDelivery { get; init; }
    public required IReadOnlyList<StatusUpdate> StatusUpdates { get; init; }
}

public sealed class StatusUpdate
{
    public required DateTimeOffset Timestamp { get; init; }
    public required string Description { get; init; }
}

using System.Net.Http.Json;

namespace sv_88c121f2d1014f65b13134f48251a575.Client.Services;

/// <summary>
/// Client-side implementation that calls the server API over HTTP.
/// Used when the component runs on WebAssembly.
/// </summary>
public sealed class HttpShipmentService(HttpClient httpClient) : IShipmentService
{
    public async Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var result = await httpClient.GetFromJsonAsync<ShipmentDetails>(
            $"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);

        return result ?? throw new InvalidOperationException("Shipment not found.");
    }
}

